302		// Implement axi_awready generation
303		// axi_awready is asserted for one S_AXI_ACLK clock cycle when both
304		// S_AXI_AWVALID and S_AXI_WVALID are asserted. axi_awready is
305		// de-asserted when reset is low.
306	
307		always @( posedge S_AXI_ACLK )
308		begin
309		  if ( S_AXI_ARESETN == 1'b0 )
310		    begin
311		      axi_awready <= 1'b0;
312		      aw_en <= 1'b1;
313		    end 
314		  else
315		    begin    
316		      if (~axi_awready && S_AXI_AWVALID && S_AXI_WVALID && aw_en)
317		        begin
318		          // slave is ready to accept write address when 
319		          // there is a valid write address and write data
320		          // on the write address and data bus. This design 
321		          // expects no outstanding transactions. 
322		          axi_awready <= 1'b1;
323		          aw_en <= 1'b0;
324		        end
325		        else if (S_AXI_BREADY && axi_bvalid)
326		            begin
327		              aw_en <= 1'b1;
328		              axi_awready <= 1'b0;
329		            end
330		      else           
331		        begin
332		          axi_awready <= 1'b0;
333		        end
334		    end 
335		end       
336	
337		// Implement axi_awaddr latching
338		// This process is used to latch the address when both 
339		// S_AXI_AWVALID and S_AXI_WVALID are valid. 
340	
341		always @( posedge S_AXI_ACLK )
342		begin
343		  if ( S_AXI_ARESETN == 1'b0 )
344		    begin
345		      axi_awaddr <= 0;
346		    end 
347		  else
348		    begin    
349		      if (~axi_awready && S_AXI_AWVALID && S_AXI_WVALID && aw_en)
350		        begin
351		          // Write Address latching 
352		          axi_awaddr <= S_AXI_AWADDR;
353		        end
354		    end 
355		end       
