371		        begin
372		          // slave is ready to accept write data when 
373		          // there is a valid write address and write data
374		          // on the write address and data bus. This design 
375		          // expects no outstanding transactions. 
376		          axi_wready <= 1'b1;
377		        end
378		      else
379		        begin
380		          axi_wready <= 1'b0;
381		        end
382		    end 
383		end       
