783		        //     for ( byte_index = 0; byte_index <= (C_S_AXI_DATA_WIDTH/8)-1; byte_index = byte_index+1 )
784		        //       if ( S_AXI_WSTRB[byte_index] == 1 ) begin
785		        //         // Respective byte enables are asserted as per write strobes 
786		        //         // Slave register 19
787		        //         slv_reg47[(byte_index*8) +: 8] <= S_AXI_WDATA[(byte_index*8) +: 8];
788		        //       end
789		          default : begin
790		                      slv_reg0 <= slv_reg0;
791		                      slv_reg1 <= slv_reg1;
792		                      slv_reg2 <= slv_reg2;
793		                      slv_reg3 <= slv_reg3;
794		                      slv_reg4 <= slv_reg4;
795		                      slv_reg5 <= slv_reg5;
796		                      slv_reg6 <= slv_reg6;
797		                      slv_reg7 <= slv_reg7;
798		                      slv_reg8 <= slv_reg8;
799		                      slv_reg9 <= slv_reg9;
800		                      slv_reg10 <= slv_reg10;
801		                      slv_reg11 <= slv_reg11;
802		                      slv_reg12 <= slv_reg12;
803		                      slv_reg13 <= slv_reg13;
804		                      //slv_reg14 <= slv_reg14;
805		                      //slv_reg15 <= slv_reg15;
806		                      slv_reg16 <= slv_reg16;
807		                      slv_reg17 <= slv_reg17;
808		                      slv_reg18 <= slv_reg18;
809		                      slv_reg19 <= slv_reg19;
