838		                    end
839		        endcase
840		      end
841		  end
842		end    
843	
844		// Implement write response logic generation
845		// The write response and response valid signals are asserted by the slave 
846		// when axi_wready, S_AXI_WVALID, axi_wready and S_AXI_WVALID are asserted.  
847		// This marks the acceptance of address and indicates the status of 
848		// write transaction.
849	
850		always @( posedge S_AXI_ACLK )
851		begin
852		  if ( S_AXI_ARESETN == 1'b0 )
853		    begin
854		      axi_bvalid  <= 0;
855		      axi_bresp   <= 2'b0;
856		    end 
857		  else
858		    begin    
859		      if (axi_awready && S_AXI_AWVALID && ~axi_bvalid && axi_wready && S_AXI_WVALID)
860		        begin
861		          // indicates a valid write response is available
862		          axi_bvalid <= 1'b1;
863		          axi_bresp  <= 2'b0; // 'OKAY' response 
864		        end                   // work error responses in future
865		      else
866		        begin
867		          if (S_AXI_BREADY && axi_bvalid) 
868		            //check if bready is asserted while bvalid is high) 
869		            //(there is a possibility that bready is always asserted high)   
870		            begin
871		              axi_bvalid <= 1'b0; 
872		            end  
873		        end
874		    end
875		end   
876	
877		// Implement axi_arready generation
878		// axi_arready is asserted for one S_AXI_ACLK clock cycle when
879		// S_AXI_ARVALID is asserted. axi_awready is 
880		// de-asserted when reset (active low) is asserted. 
881		// The read address is also latched when S_AXI_ARVALID is 
882		// asserted. axi_araddr is reset to zero on reset assertion.
883	
884		always @( posedge S_AXI_ACLK )
885		begin
886		  if ( S_AXI_ARESETN == 1'b0 )
887		    begin
888		      axi_arready <= 1'b0;
889		      axi_araddr  <= 32'b0;
890		    end 
891		  else
892		    begin    
893		      if (~axi_arready && S_AXI_ARVALID)
894		        begin
895		          // indicates that the slave has acceped the valid read address
896		          axi_arready <= 1'b1;
897		          // Read address latching
898		          axi_araddr  <= S_AXI_ARADDR;
899		        end
900		      else
901		        begin
902		          axi_arready <= 1'b0;
903		        end
904		    end 
905		end       
906	
907		// Implement axi_arvalid generation
908		// axi_rvalid is asserted for one S_AXI_ACLK clock cycle when both 
909		// S_AXI_ARVALID and axi_arready are asserted. The slave registers 
910		// data are available on the axi_rdata bus at this instance. The 
911		// assertion of axi_rvalid marks the validity of read data on the 
912		// bus and axi_rresp indicates the status of read transaction.axi_rvalid 
913		// is deasserted on reset (active low). axi_rresp and axi_rdata are 
914		// cleared to zero on reset (active low).  
915		always @( posedge S_AXI_ACLK )
916		begin
917		  if ( S_AXI_ARESETN == 1'b0 )
918		    begin
919		      axi_rvalid <= 0;
920		      axi_rresp  <= 0;
921		    end 
922		  else
923		    begin    
924		      if (axi_arready && S_AXI_ARVALID && ~axi_rvalid)
925		        begin
926		          // Valid read data is available at the read data bus
927		          axi_rvalid <= 1'b1;
928		          axi_rresp  <= 2'b0; // 'OKAY' response
929		        end   
930		      else if (axi_rvalid && S_AXI_RREADY)
931		        begin
932		          // Read data is accepted by the master
933		          axi_rvalid <= 1'b0;
934		        end                
935		    end
936		end    
937	
938		// Implement memory mapped register select and read logic generation
939		// Slave register read enable is asserted when valid address is available
940		// and the slave is ready to accept the read address.
941		assign slv_reg_rden = axi_arready & S_AXI_ARVALID & ~axi_rvalid;
942		always @(*)
943		begin
944		      // Address decoding for reading registers
945		      case ( axi_araddr[ADDR_LSB+OPT_MEM_ADDR_BITS:ADDR_LSB] )
946		        6'h00   : reg_data_out <= slv_reg0;
947		        6'h01   : reg_data_out <= slv_reg1;
948		        6'h02   : reg_data_out <= slv_reg2;
949		        6'h03   : reg_data_out <= slv_reg3;
950		        6'h04   : reg_data_out <= slv_reg4;
951		        6'h05   : reg_data_out <= slv_reg5;
952		        6'h06   : reg_data_out <= slv_reg6;
953		        6'h07   : reg_data_out <= slv_reg7;
954		        6'h08   : reg_data_out <= slv_reg8;
955		        6'h09   : reg_data_out <= slv_reg9;
956		        6'h0A   : reg_data_out <= slv_reg10;
957		        6'h0B   : reg_data_out <= slv_reg11;
958		        6'h0C   : reg_data_out <= slv_reg12;
959		        6'h0D   : reg_data_out <= slv_reg13;/*
960		        6'h0E   : reg_data_out <= slv_reg14;
961		        6'h0F   : reg_data_out <= slv_reg15;*/
962		        6'h10   : reg_data_out <= slv_reg16;
963		        6'h11   : reg_data_out <= slv_reg17;
964		        6'h12   : reg_data_out <= slv_reg18;
965		        6'h13   : reg_data_out <= slv_reg19;
966		        6'h14   : reg_data_out <= slv_reg20;
967		        6'h15   : reg_data_out <= slv_reg21;
968		        6'h16   : reg_data_out <= slv_reg22;
969		        // 6'h17   : reg_data_out <= slv_reg23;
970		        // 6'h18   : reg_data_out <= slv_reg24;
971		        // 6'h19   : reg_data_out <= slv_reg25;
972		        6'h1A   : reg_data_out <= slv_reg26;
973		        6'h1B   : reg_data_out <= slv_reg27;
974		        6'h1C   : reg_data_out <= slv_reg28;
975		        6'h1D   : reg_data_out <= slv_reg29;
976		        6'h1E   : reg_data_out <= slv_reg30;
977		        6'h1F   : reg_data_out <= slv_reg31;
978		        //6'h20   : reg_data_out <= slv_reg32;
979		        //6'h21   : reg_data_out <= slv_reg33;
980		        //6'h22   : reg_data_out <= slv_reg34;
981		        //6'h23   : reg_data_out <= slv_reg35;
982		        //6'h24   : reg_data_out <= slv_reg36;
983		        //6'h25   : reg_data_out <= slv_reg37;
984		        //6'h26   : reg_data_out <= slv_reg38;
985		        //6'h27   : reg_data_out <= slv_reg39;
