	      slv_reg15 <= 32'h0;
	      slv_reg16 <= 32'h0;
	      slv_reg17 <= 32'h0;
	      slv_reg18 <= 32'h0;
	      slv_reg19 <= 32'h0;*/
	    end 
	  else begin
	    if (slv_reg_wren)
